import React from "react";
import PayPalCheckoutButton from "./PayPalCheckoutButton";

const Details = (props) => {

    let count = 1;
    const item = props.products.length <= 1 ? "item" : "items";

    const productItem = props.products.map(product => {
        return <tr key={product.article}>
            <td>{count++}</td>
            <td>{product.article}</td>
            <td>{product.name}</td>
            <td>{product.price}</td>
            <td>{product.quantity + ' ' + product.unit}</td>
            <td>{((Number)(product.price) * product.quantity).toFixed(2)}</td>
        </tr>
    });

    const updateOrder = (order) => {
        props.ordersService.updateOrder(order);
    };

    return <React.Fragment>
        <div className="mod__content">
            <table>
                <thead >
                <tr>
                    <th>#</th>
                    <th>Product Article</th>
                    <th>Product Name</th>
                    <th>Product Price / ₪</th>
                    <th>Product Quantity </th>
                    <th>Product Total / ₪</th>
                </tr>
                </thead>
                <tbody>
                {productItem}
                </tbody>
            </table>
            <div className="table-footer">
                <div>
                    <span className="table-total table-total_subtext">Subtotal ({item} {props.products.length}):</span>
                    <span className="table-total table-total_unit">₪ </span>
                    <span className="table-total table-total_price">{props.totalPrice.toFixed(2)}</span>
                </div>
            </div>
            <div>
                { props.order.isPaid
                        ? ''
                        : <PayPalCheckoutButton  hideDetail={props.hideDetail} updateOrder={updateOrder} order={props.order} products={props.products} orderID={props.orderID} total={props.totalPrice}/>}
            </div>
        </div>
    </React.Fragment>

}
export default Details;
